var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"PHONE_VOICE_NULL_NULL","text":{"KOREA":"<b>꼬맹이</b> - <color=#ffd34c>리타 언니! 정찰 성공^_^!</color>","JPN":"<b>ガキ</b> - <color=#ffd34c>リタお姉ちゃん！　偵察成功^_^！</color>","ENG":"<b>Kid</b> - <color=#ffd34c>Rita! I found him! :)</color>","TWN":"<b>小鬼</b> - <color=#ffd34c>麗塔姐姐！偵察成功^_^！</color>"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PHONE_VOICE_NULL_NULL","text":{"KOREA":"<b>꼬맹이</b> - <color=#ffd34c>대표님이 말했던 채무자 아저씨 찾았어요!</color>","JPN":"<b>ガキ</b> - <color=#ffd34c>代表が言ってた債務者のおじさんを見つけましたよ！</color>","ENG":"<b>Kid</b> - <color=#ffd34c>I found that guy who owes the boss money!</color>","TWN":"<b>小鬼</b> - <color=#ffd34c>我找到BOSS說的那個債務人大叔了！</color>"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PHONE_VOICE_NULL_NULL","text":{"KOREA":"<b>리타</b> – <color=#ffd34c>그래. 어딘지나 말해.</color>","JPN":"<b>リタ</b> - <color=#ffd34c>そうか。場所だけ教えろ。</color>","ENG":"<b>Rita</b> - <color=#ffd34c>I see. Just tell me where he is.</color>","TWN":"<b>麗塔</b> – <color=#ffd34c>嗯，他在哪裡？</color>"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PHONE_VOICE_NULL_NULL","text":{"KOREA":"<b>꼬맹이</b> – <color=#ffd34c>안 돼요X_X!</color>","JPN":"<b>ガキ</b> - <color=#ffd34c>イヤでーすX_X！</color>","ENG":"<b>Kid</b> - <color=#ffd34c>No! :(</color>","TWN":"<b>小鬼</b> – <color=#ffd34c>不行X_X！</color>"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PHONE_VOICE_NULL_NULL","text":{"KOREA":"<b>꼬맹이</b> –<color=#ffd34c> 또 언니 혼자 가려고 그러죠? 오늘은 저도 같이 갈래요!</color>","JPN":"<b>ガキ</b> - <color=#ffd34c>また置いて行くつもりでしょう？　今日は私も一緒に行きます！</color>","ENG":"<b>Kid</b> - <color=#ffd34c>You're going to go off all by yourself again. Let me come with you this time!</color>","TWN":"<b>小鬼</b> –<color=#ffd34c>姐姐你是不是又想一個人去？今天我也要跟你一起去！</color>"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PHONE_VOICE_NULL_NULL","text":{"KOREA":"<b>리타</b> – <color=#ffd34c>알았으니까 내가 도착할 때까지 얌전히 있어.</color>","JPN":"<b>リタ</b> - <color=#ffd34c>わかったから、私が着くまで大人しく待ってろ、いいな？</color>","ENG":"<b>Rita</b> - <color=#ffd34c>Fine. Just stay put until I get there.</color>","TWN":"<b>麗塔</b> – <color=#ffd34c>知道了，在我到之前你給我老實待著。</color>"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PHONE_VOICE_NULL_NULL","text":{"KOREA":"<b>꼬맹이</b> - <color=#ffd34c>넹! 주소 보냈어요! 기다리고 있을게요!</color>","JPN":"<b>ガキ</b> - <color=#ffd34c>はいっ！　住所は送りました！　待ってまーす！</color>","ENG":"<b>Kid</b> - <color=#ffd34c>Oki! I sent you the address! I'll be waiting for you!</color>","TWN":"<b>小鬼</b> - <color=#ffd34c>好！地址發給你了！我等著你哦！</color>"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"주소대로라면 이 근처가 틀림없는데......","JPN":"あの住所だとこの辺で間違いないが……","ENG":"This should be the spot, if she gave me the right address...","TWN":"按照這個位址應該就是這附近啊……"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이 꼬맹이, 사람을 불러 놓고 그새 어디 간 거야?","JPN":"あのガキ、人を呼んでおいてどこに隠れているんだ？","ENG":"Where did that kid go anyway? I told her to stay put.","TWN":"這個小鬼，把人叫到這裡自己又跑到哪去了？"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REFUGEE_NPC_OLD_NULL","text":{"KOREA":"침식체한테 가족도 집도 전부 잃었습니다...... 제발 이 불쌍한 사람 좀 도와 주십시오......","JPN":"侵食体のせいで家族も家もすべて失いました……どうかお恵みくださいませぇ……","ENG":"I've lost my family and my home to Corrupted Objects... Please help out a poor fellow...","TWN":"侵蝕體害我失去了親人，家也沒了，……請幫幫我這個可憐人吧……"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이봐. 말 좀 묻지.","JPN":"なあ、ちょっと聞いていいか？","ENG":"Hey. Let me ask you something.","TWN":"喂，我有話問你。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REFUGEE_NPC_OLD_NULL","text":{"KOREA":"힉......!","JPN":"ヒィッ……！","ENG":"Eeek!","TWN":"噫……！"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REFUGEE_NPC_OLD_NULL","text":{"KOREA":"이, 이게 오늘 구걸해서 받은 전부입니다! 다 가져 가셔도 되니 살려만 주십시오!","JPN":"こ、これが今日の収入の全部です！　全部差し上げますので命だけは……！","ENG":"Th-this is all I managed to collect begging all day! You can have it all! Please just don't hurt me!","TWN":"這是我今天討到的全部東西了！您全拿走吧，求求您不要殺我！"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"넣어 둬. 보호비 걷으러 온 깡패인 줄 알았다면 잘못 짚었어.","JPN":"しまっておけ。ショバ代を取りにきたチンピラじゃない。","ENG":"You can keep it. I'm not some goon here to wring protection money out of you.","TWN":"收回去。我可不是來收保護費的混混。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REFUGEE_NPC_OLD_NULL","text":{"KOREA":"그...... 그럼 누구시길래......?","JPN":"あ……じゃあ、どちら様で……？","ENG":"Then... W-who are you?","TWN":"那……那您是……？"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"대충 길 잃은 어린이라고 해 두지.","JPN":"まあ、いわゆる迷子ってやつだ。","ENG":"Just someone who's lost.","TWN":"就把我當作是個迷路的小孩吧。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"일행을 찾는 중이다. 양갈래 머리를 한 꼬맹이야. 본 적 있나?","JPN":"連れを探している。ツインテールのチビなんだけど、見てないか？","ENG":"I'm looking for someone I was supposed to meet. A girl with pigtails. Have you seen her?","TWN":"我正在找我的同伴。是梳著雙馬尾的小孩，你見過嗎？"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};